  ('retired-8b44517b-moex-00191', 'retired-8b44517b', 'retired-8b44517b-moex-112-d3ff7f6b', 'sub-retired-8b44517b-08', NULL, 'single_choice', '假設有一家工廠僱用勞動（L）和資本（K）來生產手機（Q），此家工廠的生產函數為 Q=min{2L,K}， 每單位勞動和資本的價格分別是4元和3元，關於此一工廠之敘述，下列何者正確？', '["勞動和資本在生產上是完全替代的關係", "生產一台手機最少須使用1單位勞工與2單位資本", "生產技術為規模報酬遞增", "製造一台手機之最小成本為5元"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:06+00:00", "source_pdf_sha1": "a034592b855d", "answer_pdf_sha1": "2d0ff47cc94b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "133", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('retired-8b44517b-moex-00192', 'retired-8b44517b', 'retired-8b44517b-moex-112-d3ff7f6b', 'sub-retired-8b44517b-08', NULL, 'single_choice', '下列何者長期可能發展成為自然獨占廠商？', '["長期平均成本曲線隨著產量增加而呈現平緩拉長的U型", "長期平均成本曲線隨著產量增加而呈現陡峭直立的U型", "長期平均成本曲線隨著產量增加而呈現正斜率、一路上升", "長期平均成本曲線隨著產量增加而呈現負斜率、一路下降"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:06+00:00", "source_pdf_sha1": "a034592b855d", "answer_pdf_sha1": "2d0ff47cc94b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "133", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('retired-8b44517b-moex-00193', 'retired-8b44517b', 'retired-8b44517b-moex-112-d3ff7f6b', 'sub-retired-8b44517b-08', NULL, 'single_choice', '考慮一完全競爭廠商A，其目標為利潤最大化。有關廠商A在短期的價格和產量決策，下列敘述', '["在廠商A所選定的產量水準下，邊際收入等於邊際成本", "在廠商A所選定的產 量水準下，價格一定高於或等於平均成本", "在廠商 A 所選定的產量水準下，價格一定高於或 等於平均變動成本", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:06+00:00", "source_pdf_sha1": "a034592b855d", "answer_pdf_sha1": "2d0ff47cc94b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "133", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "retired", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('retired-8b44517b-moex-00194', 'retired-8b44517b', 'retired-8b44517b-moex-112-d3ff7f6b', 'sub-retired-8b44517b-08', NULL, 'single_choice', '技術進步提高資本的邊際產出價值，將  ①  資本的租金，因為  ②  。', '["", "提高；", "資本供給曲線左移", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:06+00:00", "source_pdf_sha1": "a034592b855d", "answer_pdf_sha1": "2d0ff47cc94b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "133", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "retired", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('retired-8b44517b-moex-00195', 'retired-8b44517b', 'retired-8b44517b-moex-112-d3ff7f6b', 'sub-retired-8b44517b-08', NULL, 'single_choice', '假設消費者的 vonNeumann-Morgenstern 效用函數為 U(y)=y0.5，其中 y 為所得。下列敘述何者 正確？', '["此消費者為風險趨避者", "此消費者為風險愛好者", "此消費者為風險中立者", "無法根據此效用函數判斷消費者為風險趨避、愛好或是中立者"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:06+00:00", "source_pdf_sha1": "a034592b855d", "answer_pdf_sha1": "2d0ff47cc94b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "133", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('retired-8b44517b-moex-00196', 'retired-8b44517b', 'retired-8b44517b-moex-112-d3ff7f6b', 'sub-retired-8b44517b-08', NULL, 'single_choice', '假設經濟體系中有兩位消費者（A和B），兩種財貨（X和Y）。消費者A的初始稟賦為（X= 30,Y=20）而消費者B的初始稟賦為（X=20,Y=30）。消費者A的效用函數為 U(X,Y)=XY， 而消費者 B 的效用函數則為 U(X,Y) = X + Y。下列何種資源配置滿足柏瑞圖最適（Pareto efficiency）的定義？', '["A（X=30,Y=20），B（X=20,Y=30）", "A（X=20,Y=30），B（X=30,Y=20）", "A（X=15,Y=25），B（X=35,Y=25）", "A（X=10,Y=10），B（X=40,Y=40）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:06+00:00", "source_pdf_sha1": "a034592b855d", "answer_pdf_sha1": "2d0ff47cc94b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "133", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('retired-8b44517b-moex-00197', 'retired-8b44517b', 'retired-8b44517b-moex-112-d3ff7f6b', 'sub-retired-8b44517b-08', NULL, 'single_choice', '當經濟體系「所得分配」愈平均時，下列何種情況會發生？', '["吉尼係數（Ginicoefficient）愈接近於0，羅倫茲曲線（LorenzCurve）與45度直線之間包圍面 積愈大", "吉尼係數（Ginicoefficient）愈接近於0，羅倫茲曲線（LorenzCurve）與45度直線之間包圍面 積愈小", "吉尼係數（Ginicoefficient）愈接近於1，羅倫茲曲線（LorenzCurve）與45度直線之間包圍面 積愈小", "吉尼係數（Ginicoefficient）愈接近於1，羅倫茲曲線（LorenzCurve）與45度直線之間包圍面 積愈大"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:06+00:00", "source_pdf_sha1": "a034592b855d", "answer_pdf_sha1": "2d0ff47cc94b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "133", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('retired-8b44517b-moex-00198', 'retired-8b44517b', 'retired-8b44517b-moex-112-d3ff7f6b', 'sub-retired-8b44517b-08', NULL, 'single_choice', '當實質利率低於其均衡水準時，下列敘述何者正確？', '["貸款人（lender）將找不到借款人（borrower）借走所有可用資金，實質利率將下降", "借款人將無法借到足夠的資金，實質利率將上升", "貸款人將找不到借款人借走所有可用資金，實質利率將上升", "借款人將無法借到足夠的資金，實質利率將下降"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:06+00:00", "source_pdf_sha1": "a034592b855d", "answer_pdf_sha1": "2d0ff47cc94b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "133", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('retired-8b44517b-moex-00199', 'retired-8b44517b', 'retired-8b44517b-moex-112-d3ff7f6b', 'sub-retired-8b44517b-08', NULL, 'single_choice', '假設A國為一封閉體系。A國的GDP為新臺幣20兆元，政府每年購買價值3兆元的財貨及勞 務，政府每年收到4兆元的稅，及提供2兆元的移轉性支付給家計單位，A國的私部門儲蓄為4 兆元。下列敘述何者正確？', '["A國的均衡消費金額為10兆元，A國的均衡投資金額為3兆元", "A國的均衡消費金額為12兆元，A國的均衡投資金額為4兆元", "A國的均衡消費金額為14兆元，A國的均衡投資金額為3兆元", "A國的均衡消費金額為15兆元，A國的均衡投資金額為5兆元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:06+00:00", "source_pdf_sha1": "a034592b855d", "answer_pdf_sha1": "2d0ff47cc94b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "133", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "勞工行政"}'::jsonb, NULL)
